import base64, os, sys

data = ""
content = base64.b64decode(data)
path = os.path.join('src', 'App.jsx')

# Force overwrite
with open(path, 'wb') as f:
    f.write(content)

# Verify
with open(path, 'rb') as f:
    written = f.read()

if written == content:
    lines = content.decode('utf-8').count(chr(10))
    print(f'SUCESSO! {lines} linhas escritas corretamente.')
else:
    print('ERRO: arquivo nao foi escrito corretamente!')
    sys.exit(1)
